    private static final EnumSet<LnedefRegBv> NIET_BELASTBARE_REGIMES = EnumSet
            .of(LnedefRegBv.NVT, LnedefRegBv.VD_BV_10_KWG__NBB, LnedefRegBv.NBB_NFF, LnedefRegBv.VD_BV_10_FTSW_NBB, LnedefRegBv.VD_BV_10_MOB_VERG_NBB,
                    LnedefRegBv.VD_BV_50_VAC_TOE_NBB, LnedefRegBv.VD_BV_50_KOSTEN_NBB);

    private static final EnumSet<LnedefRegBv> BV_GEWOON_REGIMES = EnumSet
            .of(LnedefRegBv.VD_BV_10_BZ___GB, LnedefRegBv.VD_BV_10_UKZI_GB, LnedefRegBv.VD_BV_10_UKAG_GB, LnedefRegBv.VD_BV_10_VVAA_GB,
                    LnedefRegBv.VD_BV_10_VVAA_GB_AFTROK_SOC_INH, LnedefRegBv.VD_BV_10_VVAA_GB_BRUTO, LnedefRegBv.VD_BV_10_AWWV_gb,
                    LnedefRegBv.VD_BV_10_OVERWERK, LnedefRegBv.VD_BV_11_PENS_GB, LnedefRegBv.VD_BV_10_MOB_VERG_INLV_WAGEN);

    private static final String CONTROLEER_NETTO_BRUTO_SQL =
            "select rh.opdrachtid,rh.begindatum,rh.einddatum,(case when vak_refjaar is null then 0 else 1 end) as tp,0 as kode,0 as ext,sum(nvl(bruto.bedrag,0)) as bruto, sum(nvl(netto.bedrag,0))as netto from rekenhoofd rh"
                    + " join rekenlijn rl on rl.rekenhoofdid=rh.id " + " left join rekenbedrag bruto on bruto.rekenlijnid=rl.id and bruto.bedragtypectid="
                    + RekenBedragType.BRUTO_MAANDLOON.getId() + " left join rekenbedrag netto on netto.rekenlijnid=rl.id and netto.bedragtypectid="
                    + RekenBedragType.NETTO.getId() + " where rh.opdrachtid=? and rh.begindatum=?  "
                    +
                    " group by rh.opdrachtid,rh.begindatum,rh.einddatum,4 having sum(nvl(bruto.bedrag,0))<sum(nvl(netto.bedrag,0)) or sum(nvl(netto.bedrag,0))>4000 or (sum(nvl(netto.bedrag,0))<1 and sum(nvl(netto.bedrag,0))!=0)";

    private static final String INHOUDINGEN_SQL =
            "select rh.opdrachtid,rh.begindatum,rh.einddatum,ked.tp,ked.kode,ked.ext, sum(nvl(netto.bedrag,0))as netto from rekenhoofd rh"
                    + " join rekenlijn rl on rl.rekenhoofdid=rh.id" + " left join rekenbedrag netto on netto.rekenlijnid=rl.id and netto.bedragtypectid="
                    + RekenBedragType.NETTO.getId() + " left join gl__kode_ext_def ked on ked.ake_id=rl.akeid"
                    + " where rh.opdrachtid=? and rh.begindatum=? and aard=4" + " group by rh.opdrachtid,rh.begindatum,rh.einddatum,ked.tp,ked.kode,ked.ext"
                    + " having sum(nvl(netto.bedrag,0))!=0";

    private static final String CONTROLEER_SOM_BRUTO_PER_LOONCODE_SQL =
            "select rh.opdrachtid,rh.begindatum,rh.einddatum,ked.tp,ked.kode,0 as ext,sum(nvl(bruto.bedrag,0)) as bruto, sum(nvl(bassi.bedrag,0))as bassi from rekenhoofd rh "
                    + " join rekenlijn rl on rl.rekenhoofdid=rh.id "
                    + " join gl__kode_ext_def ked on ked.ake_id=rl.akeid and ked.kode not in (1101,1140,1315,1350) "
                    + " left join rekenbedrag bruto on bruto.rekenlijnid=rl.id and bruto.bedragtypectid=" + RekenBedragType.BRUTO_MAANDLOON.getId()
                    + " left join rekenbedrag bassi on bassi.rekenlijnid=rl.id and bassi.bedragtypectid=" + RekenBedragType.BASIS_SOCIALE_INHOUDINGEN.getId()
                    + " where rh.opdrachtid=? and rh.begindatum=? "
                    + " group by rh.opdrachtid,rh.begindatum,rh.einddatum,ked.tp,ked.kode having sum(nvl(bruto.bedrag,0))<0 or sum(nvl(bassi.bedrag,0))<0 ";

    private static final String CONTROLEER_SOM_BRUTO_PER_LOONCODE_PER_ELEM_PERIODE_SQL =
            "select rh.opdrachtid,rl.begindatum,rl.einddatum,ked.tp,ked.kode,0 as ext,sum(nvl(bruto.bedrag,0)) as bruto, sum(nvl(bassi.bedrag,0))as bassi from rekenhoofd rh "
                    + " join rekenlijn rl on rl.rekenhoofdid=rh.id "
                    + " join gl__kode_ext_def ked on ked.ake_id=rl.akeid and ked.kode not in (1101,1140,1315,1350) "
                    + " left join rekenbedrag bruto on bruto.rekenlijnid=rl.id and bruto.bedragtypectid=" + RekenBedragType.BRUTO_MAANDLOON.getId()
                    + " left join rekenbedrag bassi on bassi.rekenlijnid=rl.id and bassi.bedragtypectid=" + RekenBedragType.BASIS_SOCIALE_INHOUDINGEN.getId()
                    + " where rh.opdrachtid=? and rl.begindatum>=? and rl.einddatum<=? "
                    + " group by rh.opdrachtid,rl.begindatum,rl.einddatum,ked.tp,ked.kode having sum(nvl(bruto.bedrag,0))<0 or sum(nvl(bassi.bedrag,0))<0";

    private static final String CONTROLEER_RSZ_WERKBONUS_SQL =
            "select rh.opdrachtid,rh.begindatum,rh.einddatum,0 as tp,0 as kode,0 as ext,sum(nvl(rsz.bedrag,0)) as rsz, sum(nvl(werkbonus.bedrag,0))as werkbonus from rekenhoofd rh "
                    + " join rekenlijn rl on rl.rekenhoofdid=rh.id " + " left join rekenbedrag rsz on rsz.rekenlijnid=rl.id and rsz.bedragtypectid in ("
                    + RekenBedragType.BIJDRAGE_RSZ.getId() + "," + RekenBedragType.BIJDRAGE_TAO.getId() + ")"
                    + " left join rekenbedrag werkbonus on werkbonus.rekenlijnid=rl.id and werkbonus.bedragtypectid in ("
                    + RekenBedragType.WERKBONUS_LAGE_LONEN.getId() + "," + RekenBedragType.WERKBONUS_HEEL_LAGE_LONEN.getId() + "," +
                    RekenBedragType.VERMINDERING_HERSTRUCTERING.getId() + ") "
                    + " where rh.opdrachtid=? and rh.begindatum=? "
                    + " group by rh.opdrachtid,rh.begindatum,rh.einddatum having sum(nvl(rsz.bedrag,0))<sum(nvl(werkbonus.bedrag,0)); ";

    private static final String CONTROLEER_AANWEZIGHEID_WEDDEBIJSLAG_KOPPELING_SQL =
            "select distinct rh.opdrachtid,rh.begindatum,rh.einddatum,ked.kode,ked.ext from rekenhoofd rh "
                    + "join rekenlijn rl on rl.rekenhoofdid=rh.id " + "join gl__kode_ext_def ked on ked.ake_id=rl.akeid "
                    + "and ked.kode in (503,510,512,557,558,853,854,855,903,910,912,914,916,918,919,921,957,958) "
                    + "left join weddebijslag_koppeling wbk on wbk.tijdperk=ked.tp and wbk.aard=ked.aard " + "and wbk.code=ked.kode and wbk.extensie=ked.ext "
                    + "where rh.opdrachtid=? and rh.begindatum=? and wbk.id is null";

    private static final String CONTROLEER_BV_EN_BB_OPDRACHT_MAAND_SQL =
            "select rh.opdrachtid,rh.begindatum,rh.einddatum,rh.fiscaal_jaar,sum(nvl(bv.bedrag,0)) as bv, sum(nvl(bb.bedrag,0))as bb from rekenhoofd rh "
                    + "join rekenlijn rl on rl.rekenhoofdid=rh.id "
                    + "left join rekenbedrag bv on bv.rekenlijnid=rl.id and (bv.bedragtypectid=4526 or bv.bedragtypectid=4525) "
                    + "left join rekenbedrag bb on bb.rekenlijnid=rl.id and bb.bedragtypectid=4521 "
                    + "where rh.opdrachtid=? and rh.begindatum=? and rh.fiscaal_jaar=? and regimebvctid not in " + toCtIdString(NIET_BELASTBARE_REGIMES)
                    + "group by rh.opdrachtid,rh.begindatum,rh.einddatum,rh.fiscaal_jaar "
                    + "having sum(nvl(bv.bedrag,0))<0 or (sum(nvl(bb.bedrag,0))<sum(nvl(bv.bedrag,0)) and sum(nvl(bv.bedrag,0))!=0) ";

    private static final String CONTROLEER_BV_EN_BB_PERSOON_MAAND_SQL =
            "select om.persoonid,rh.begindatum,rh.einddatum,rh.fiscaal_jaar,sum(nvl(bv.bedrag,0)) as bv, sum(nvl(bb.bedrag,0))as bb from  rekenhoofd rh "
                    + "join rekenlijn rl on rl.rekenhoofdid=rh.id " + "left join opdracht_master om on om.id=rh.opdrachtid "
                    + "left join rekenbedrag bv on bv.rekenlijnid=rl.id and (bv.bedragtypectid=4526 or bv.bedragtypectid=4525) "
                    + "left join rekenbedrag bb on bb.rekenlijnid=rl.id and bb.bedragtypectid=4521 "
                    + "where om.persoonid=? and rh.begindatum=? and rh.fiscaal_jaar=? and regimebvctid not in " + toCtIdString(NIET_BELASTBARE_REGIMES)
                    + "group by om.persoonid,rh.begindatum,rh.einddatum,rh.fiscaal_jaar "
                    + "having sum(nvl(bb.bedrag,0))<sum(nvl(bv.bedrag,0)) and sum(nvl(bv.bedrag,0))!=0";

    private static final String CONTROLEER_BV_ZERO_AND_VAKG_OR_EJT_SQL =
            "select om.persoonid,rh.begindatum,rh.einddatum,0 as fiscaal_jaar, sum(nvl(bb.bedrag,0))as bb,sum(nvl(bv.bedrag,0)) as bv from  rekenhoofd rh "
                    + "left join rekenlijn rl on rl.rekenhoofdid=rh.id  " + "left join gl__kode_ext_def ked on ked.ake_id=rl.akeid "
                    + "left join opdracht_master om on om.id=rh.opdrachtid "
                    + "left join rekenbedrag bv on bv.rekenlijnid=rl.id and (bv.bedragtypectid=4526 or bv.bedragtypectid=4525) "
                    + "left join rekenbedrag bb on bb.rekenlijnid=rl.id and bb.bedragtypectid=4521 "
                    + "where om.persoonid=? and rh.begindatum=? and (ked.is_vakgeld  in (1,4,5) or ked.is_ejt =1 or ked.kode=917) "
                    + "group by om.persoonid,rh.begindatum,rh.einddatum " + "having sum(nvl(bv.bedrag,0))==0 and sum(nvl(bb.bedrag,0))>0";

    private static final String LIST_AKEID_VAKG_OR_EJT_SQL =
            "select rh.opdrachtid,rh.begindatum,rh.einddatum, ked.tp, ked.kode, ked.ext, rl.akeid, sum(nvl(bb.bedrag,0))as bb,sum(nvl(bv.bedrag,0)) as bv from  rekenhoofd rh "
                    + "left join rekenlijn rl on rl.rekenhoofdid=rh.id  " + "left join gl__kode_ext_def ked on ked.ake_id=rl.akeid "
                    + "left join opdracht_master om on om.id=rh.opdrachtid "
                    + "left join rekenbedrag bv on bv.rekenlijnid=rl.id and (bv.bedragtypectid=4526 or bv.bedragtypectid=4525) "
                    + "left join rekenbedrag bb on bb.rekenlijnid=rl.id and bb.bedragtypectid=4521 "
                    + "where om.persoonid=? and rh.begindatum=? and (ked.is_vakgeld  in (1,4,5) or ked.is_ejt =1 or ked.kode=917) "
                    + "group by rh.opdrachtid,rh.begindatum,rh.einddatum, ked.tp, ked.kode, ked.ext, rl.akeid " +
                    "having sum(nvl(bv.bedrag,0))==0 and sum(nvl(bb.bedrag,0))>0";

    private static final String CONTROLEER_BB_GB_IS_NOT_ZERO_SQL =
            "select om.persoonid,rh.begindatum,rh.einddatum,0 as fiscaal_jaar, sum(nvl(bb.bedrag,0))as bb from  rekenhoofd rh "
                    + "left join rekenlijn rl on rl.rekenhoofdid=rh.id " + "left join gl__kode_ext_def ked on ked.ake_id=rl.akeid "
                    + "left join opdracht_master om on om.id=rh.opdrachtid " + "left join rekenbedrag bb on bb.rekenlijnid=rl.id and bb.bedragtypectid=4521 "
                    + "where om.persoonid=? and rh.begindatum=? " + "and regimebvctid in " + toCtIdString(BV_GEWOON_REGIMES) + " and ked.aard = 11 "
                    + "group by om.persoonid,rh.begindatum,rh.einddatum " + "having sum(nvl(bb.bedrag,0))!=0";

    @Override
