    public List<ControleData> bepaalControleDataNettoEnBruto(Admin admin, Opdracht opdracht, LocalDate datum) {
        entityManager.flush();
        JdbcTemplate jdbc = new JdbcTemplate(dataSource);
        Object[] args = new Object[2];
        args[0] = new SqlParameterValue(Types.INTEGER, opdracht.getId());
        args[1] = new SqlParameterValue(Types.DATE, new java.sql.Date(datum.toDate().getTime()));
        return jdbc.query(CONTROLEER_NETTO_BRUTO_SQL, new ControleDataRowMapper("bruto", "netto"), args);
    }

