    public static class ControleDataRowMapper implements RowMapper<ControleData> {

        private Set<String> bedragColumnKeys;

        public ControleDataRowMapper(String... bedragColumnKeys) {
            this.bedragColumnKeys = ImmutableSet.copyOf(bedragColumnKeys);
        }

        @Override
        public ControleData mapRow(ResultSet rs, int rowNum) throws SQLException {
            DateColumnLocalDateMapper localDateMapper = new DateColumnLocalDateMapper();
            ControleData controleData = new ControleData();
            controleData.setOpdrachtId(rs.getInt("opdrachtid"));
            controleData.setBeginDatum(localDateMapper.fromNonNullValue(rs.getDate("begindatum")));
            controleData.setEindDatum(localDateMapper.fromNonNullValue(rs.getDate("einddatum")));
            controleData.setTp(rs.getInt("tp"));
            controleData.setKode(rs.getInt("kode"));
            controleData.setExt(rs.getInt("ext"));
            for (String key : bedragColumnKeys) {
                controleData.getBedragen().put(key, new Money(rs.getBigDecimal(key)));
            }
            return controleData;
        }
    }

