    private static String toCtIdString(Collection<? extends CodeEnum> codeEnums) {
        StringBuilder ctIdString = new StringBuilder("(");
        boolean first = true;
        for (CodeEnum codeEnum : codeEnums) {
            if (first) {
                first = false;
            } else {
                ctIdString.append(",");
            }
            ctIdString.append(codeEnum.getId());
        }
        ctIdString.append(")");
        return ctIdString.toString();
